mapper.select:
SELECT inventory_id, store_id, variant_id, quantity, min_quantity, updated_at
FROM store_inventory
WHERE store_id = #{storeId} AND variant_id = #{variantId}

mapper.update:
UPDATE store_inventory
SET quantity = #{quantity}, updated_at = GETDATE()
WHERE store_id = #{storeId} AND variant_id = #{variantId}

UPDATE store_inventory
SET quantity = quantity + #{delta}, updated_at = GETDATE()
WHERE store_id = #{storeId} AND variant_id = #{variantId}
